<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('sales.manage');$id=(int)vp3_input('id');$row=null;if($id){$s=vp3_db()->prepare('SELECT * FROM service_packages WHERE id=?');$s->execute([$id]);$row=$s->fetch();if(!$row){http_response_code(404);exit('Package not found.');}}if(vp3_method()==='POST'){vp3_verify_csrf();$action=vp3_input('action','save');if($action==='item'&&$id){$label=vp3_input('label');if($label!=='')vp3_db()->prepare('INSERT INTO service_package_items(package_id,item_type,label,description,quantity,unit,sort_order,created_at) VALUES (?,?,?,?,NULLIF(?,0),NULLIF(?,\'\'),?,NOW())')->execute([$id,vp3_input('item_type','deliverable'),$label,vp3_input('item_description'),(float)vp3_input('quantity','0'),vp3_input('unit'),(int)vp3_input('sort_order','0')]);}else{$uuid=(string)($row['package_uuid']??vp3_uuid());$slug=preg_replace('/[^a-z0-9-]/','',strtolower(vp3_input('slug')))?:'';$data=[vp3_input('package_key'),vp3_input('name'),$slug,vp3_input('short_description'),vp3_input('description'),vp3_input('category','creative'),vp3_input('billing_type','one_time'),max(0,(int)vp3_input('price_cents')),max(0,(int)vp3_input('setup_fee_cents')),strtoupper(vp3_input('currency','USD')),max(0,(int)vp3_input('delivery_days'))?:null,max(0,(int)vp3_input('featured_rank')),vp3_input('status','draft')];if($id){vp3_db()->prepare('UPDATE service_packages SET package_key=?,name=?,slug=?,short_description=?,description=?,category=?,billing_type=?,price_cents=?,setup_fee_cents=?,currency=?,delivery_days=?,featured_rank=?,status=?,updated_at=NOW() WHERE id=?')->execute([...$data,$id]);}else{vp3_db()->prepare('INSERT INTO service_packages(package_uuid,package_key,name,slug,short_description,description,category,billing_type,price_cents,setup_fee_cents,currency,delivery_days,featured_rank,status,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW(),NOW())')->execute([$uuid,...$data]);$id=(int)vp3_db()->lastInsertId();}vp3_audit('admin',(int)$admin['id'],'service_package.saved','service_package',$uuid,['id'=>$id]);}vp3_flash('success','Service package updated.');vp3_redirect('admin/service-package.php?id='.$id);}if($id){$s=vp3_db()->prepare('SELECT * FROM service_packages WHERE id=?');$s->execute([$id]);$row=$s->fetch();}$items=[];if($id){$s=vp3_db()->prepare('SELECT * FROM service_package_items WHERE package_id=? ORDER BY sort_order,id');$s->execute([$id]);$items=$s->fetchAll();}$pageTitle=$row?'Edit Service Package':'Add Service Package';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Offer catalog</span><h1><?=vp3_e($pageTitle)?></h1></div><a class="button secondary" href="service-packages.php">Back</a></div><form class="card admin-form" method="post"><?=vp3_csrf_field()?><div class="admin-form-grid"><div class="field"><label>Package key</label><input name="package_key" required value="<?=vp3_e($row['package_key']??'')?>"></div><div class="field"><label>Name</label><input name="name" required value="<?=vp3_e($row['name']??'')?>"></div><div class="field"><label>Slug</label><input name="slug" pattern="[a-z0-9-]+" required value="<?=vp3_e($row['slug']??'')?>"></div><div class="field"><label>Category</label><select name="category"><?php foreach(['platform','creative','launch','management','custom'] as $v):?><option <?=($row['category']??'creative')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field full"><label>Short description</label><textarea name="short_description"><?=vp3_e($row['short_description']??'')?></textarea></div><div class="field full"><label>Description</label><textarea name="description"><?=vp3_e($row['description']??'')?></textarea></div><div class="field"><label>Billing type</label><select name="billing_type"><?php foreach(['one_time','monthly','yearly','custom'] as $v):?><option <?=($row['billing_type']??'one_time')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Price in cents</label><input name="price_cents" type="number" min="0" value="<?=vp3_e($row['price_cents']??0)?>"></div><div class="field"><label>Setup fee in cents</label><input name="setup_fee_cents" type="number" min="0" value="<?=vp3_e($row['setup_fee_cents']??0)?>"></div><div class="field"><label>Currency</label><input name="currency" maxlength="3" value="<?=vp3_e($row['currency']??'USD')?>"></div><div class="field"><label>Delivery days</label><input name="delivery_days" type="number" min="0" value="<?=vp3_e($row['delivery_days']??'')?>"></div><div class="field"><label>Featured rank</label><input name="featured_rank" type="number" min="0" value="<?=vp3_e($row['featured_rank']??0)?>"></div><div class="field"><label>Status</label><select name="status"><?php foreach(['draft','active','retired'] as $v):?><option <?=($row['status']??'draft')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div></div><button class="button">Save package</button></form><?php if($id):?><section class="admin-section admin-split"><div><h2>Package items</h2><div class="activity-list"><?php foreach($items as $item):?><article><strong><?=vp3_e($item['label'])?></strong><span><?=vp3_e($item['item_type'].' · '.$item['unit'])?></span><p><?=vp3_e($item['description'])?></p></article><?php endforeach;?></div></div><form class="card" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="item"><h3>Add package item</h3><div class="field"><label>Label</label><input name="label" required></div><div class="field"><label>Type</label><select name="item_type"><option>deliverable</option><option>feature</option><option>limit</option><option>support</option><option>timeline</option></select></div><div class="field"><label>Description</label><textarea name="item_description"></textarea></div><div class="field"><label>Quantity</label><input name="quantity" type="number" step="0.01"></div><div class="field"><label>Unit</label><input name="unit"></div><div class="field"><label>Sort order</label><input name="sort_order" type="number" value="0"></div><button class="button small">Add item</button></form></section><?php endif;?>
